// // This module captures input data on the falling edge of the clock signal when the write enable signal (we) is deasserted.
module top_module(clk,we, din, dout);parameter WIDTH=32; 
 input we; 
 input clk; 
 input [WIDTH-1:0] din; 
 output [WIDTH-1:0] dout; 
 reg [WIDTH-1:0] store; 
 always @(posedge clk) 
  if(we) 
  store <= din; 
 assign dout = store ; 
 endmodule
